import{_ as a,o as d,c as e,a0 as r}from"./chunks/framework.AQcSKqPn.js";const g=JSON.parse('{"title":"AI实验室 - 小红书首篇文案","description":"","frontmatter":{"type":"page","title":"AI实验室 - 小红书首篇文案","tags":["xiaohongshu","enterprise-ai","agent-os","social-post"],"created":"2026-07-18T00:00:00.000Z"},"headers":[],"relativePath":"social_posts/enterprise-ai-first-post-2026-07-18.md","filePath":"social_posts/enterprise-ai-first-post-2026-07-18.md","lastUpdated":1784513544000}'),o={name:"social_posts/enterprise-ai-first-post-2026-07-18.md"};function i(n,t,s,h,l,p){return d(),e("div",null,[...t[0]||(t[0]=[r('<h1 id="小红书首篇文案-ai实验室-企业ai落地实践" tabindex="-1">小红书首篇文案 - AI实验室（企业AI落地实践） <a class="header-anchor" href="#小红书首篇文案-ai实验室-企业ai落地实践" aria-label="Permalink to &quot;小红书首篇文案 - AI实验室（企业AI落地实践）&quot;">​</a></h1><h2 id="账号信息" tabindex="-1">账号信息 <a class="header-anchor" href="#账号信息" aria-label="Permalink to &quot;账号信息&quot;">​</a></h2><table tabindex="0"><thead><tr><th>项目</th><th>内容</th></tr></thead><tbody><tr><td><strong>账号名</strong></td><td>AI实验室</td></tr><tr><td><strong>定位</strong></td><td>企业AI落地实践</td></tr><tr><td><strong>产品</strong></td><td>自研Agent OS</td></tr><tr><td><strong>核心场景</strong></td><td>财务报销审核、AI客服、图纸提取文字、知识库</td></tr><tr><td><strong>用户画像</strong></td><td>中小企业</td></tr></tbody></table><h2 id="发布内容" tabindex="-1">发布内容 <a class="header-anchor" href="#发布内容" aria-label="Permalink to &quot;发布内容&quot;">​</a></h2><h3 id="标题" tabindex="-1">标题 <a class="header-anchor" href="#标题" aria-label="Permalink to &quot;标题&quot;">​</a></h3><blockquote><p>小公司做AI一年，我把我踩的坑和自研的Agent OS全公开了</p></blockquote><h3 id="正文" tabindex="-1">正文 <a class="header-anchor" href="#正文" aria-label="Permalink to &quot;正文&quot;">​</a></h3><p>去年年初我们决定做一件事：用AI把公司内部跑通。结果发现市面上的企业AI工具要么贵得离谱，要么根本不适合中小企业的真实场景。</p><p>于是我们自己搭了一套Agent OS，现在财务报销审核、客服、图纸文字提取、知识库都在上面跑。不吹，说几个真实效果：</p><p>💰 财务报销审核：原来财务3个人审核80份报销单要两天，现在agent自动核对发票金额、税号、合规性，有问题标记出来推给人工，一上午搞定。</p><p>🤖 AI客服：不是那种一问三不知的聊天机器人。我们搭了工单闭环——客户问问题 → agent查知识库 → 需要人工的自动转工单带上下文。客服从3人降到1人，响应时间从4小时缩到3分钟。</p><p>📐 图纸文字提取：建筑行业的图纸，以前要人工一个个看标注、提取数据。现在agent自动OCR+结构化输出，丢进去直接出表格。</p><p>📚 企业知识库：把公司所有文档、制度、SOP丢进去，员工直接问就行。新人培训时间从两周缩到三天。</p><p>我最大的感受：企业AI落地根本不是大模型够不够强的问题，而是怎么把agent编排得对、怎么跟企业现有流程接上。</p><p>我们的Agent OS就是专门解决这个的——轻量、可配置、跟中小企业预算匹配。</p><p>如果你们公司也在折腾AI落地，欢迎交流。</p><h3 id="标签" tabindex="-1">标签 <a class="header-anchor" href="#标签" aria-label="Permalink to &quot;标签&quot;">​</a></h3><p>#AI实验室 #企业AI #AgentOS #AI落地 #中小企业AI #数字化 #智能客服 #企业知识库 #报销系统 #AI智能体</p><h2 id="图片清单" tabindex="-1">图片清单 <a class="header-anchor" href="#图片清单" aria-label="Permalink to &quot;图片清单&quot;">​</a></h2><table tabindex="0"><thead><tr><th>编号</th><th>用途</th><th>文件名</th><th>尺寸</th><th>大小</th></tr></thead><tbody><tr><td>P1</td><td>封面</td><td>p1.png</td><td>665×886</td><td>~90KB</td></tr><tr><td>P2</td><td>财务报销审核场景</td><td>p2.png</td><td>665×886</td><td>~90KB</td></tr><tr><td>P3</td><td>AI客服场景</td><td>p3.png</td><td>665×886</td><td>~61KB</td></tr><tr><td>P4</td><td>图纸提取文字场景</td><td>p4.png</td><td>665×886</td><td>~85KB</td></tr><tr><td>P5</td><td>企业知识库场景</td><td>p5.png</td><td>665×886</td><td>~85KB</td></tr><tr><td>P6</td><td>团队协作场景</td><td>p6.png</td><td>665×886</td><td>~96KB</td></tr><tr><td>Avatar</td><td>账号头像</td><td>avatar.png</td><td>500×500</td><td>~21KB</td></tr></tbody></table><h2 id="图片路径" tabindex="-1">图片路径 <a class="header-anchor" href="#图片路径" aria-label="Permalink to &quot;图片路径&quot;">​</a></h2><p>所有图片位于：<code>/root/.hermes/enterprise_content/images/</code></p><h2 id="发布说明" tabindex="-1">发布说明 <a class="header-anchor" href="#发布说明" aria-label="Permalink to &quot;发布说明&quot;">​</a></h2><ul><li>新账号「AI实验室」，首次发布</li><li>手动上传模式（新账号无自动化发布通道）</li><li>图片为 Pollinations.ai 生成，企业科技风格</li></ul>',24)])])}const A=a(o,[["render",i]]);export{g as __pageData,A as default};
